    def encrypt_card_number(self, card_number: str) -> str:
        """
        Encrypt a credit card number.

        Args:
            card_number: The credit card number (digits only, 13-19 characters).

        Returns:
            Base64-encoded string containing: key_version || nonce || ciphertext || tag
            Safe for storage in a database text/varchar column.
        """
