class KeyManager:
    """
    Manages encryption keys with versioning support for key rotation.

    In production, this should interface with a secrets manager:
    - AWS Secrets Manager
    - HashiCorp Vault
    - Azure Key Vault
    - Google Cloud Secret Manager

    This implementation demonstrates the interface; replace the storage
    backend with your secrets manager client.
    """

    def __init__(self):
        self._keys: dict[int, bytes] = {}
        self._current_version: int = 0

    def load_key_from_secrets_manager(self, version: int, key: bytes) -> None:
        """
        Register a key version. In production, this would fetch from
        your secrets manager rather than accepting the key directly.
        """
        if len(key) != 32:
            raise ValueError("Key must be 32 bytes")
        self._keys[version] = key
        if version > self._current_version:
            self._current_version = version

    def get_current_encryptor(self) -> CreditCardEncryptor:
        """Get an encryptor using the current (latest) key version."""
        if self._current_version == 0:
            raise RuntimeError("No keys loaded")
        key = self._keys[self._current_version]
        return CreditCardEncryptor(key, self._current_version)

    def get_decryptor(self, encrypted_card: str) -> CreditCardEncryptor:
        """
        Get the appropriate decryptor based on the key version
        embedded in the encrypted data.
        """
        try:
            encrypted_blob = base64.urlsafe_b64decode(encrypted_card.encode("ascii"))
        except Exception:
            raise ValueError("Invalid encrypted data")

        if len(encrypted_blob) < 1:
            raise ValueError("Invalid encrypted data")

        key_version = encrypted_blob[0]
        if key_version not in self._keys:
            raise ValueError(
                f"Key version {key_version} not found. "
                f"Ensure all key versions are loaded from your secrets manager."
            )

        return CreditCardEncryptor(self._keys[key_version], key_version)


def _luhn_check(card_number: str) -> bool:
    """Validate a card number using the Luhn algorithm."""
    digits = [int(d) for d in card_number]
    digits.reverse()
    checksum = 0
    for i, d in enumerate(digits):
        if i % 2 == 1:
            d *= 2
            if d > 9:
                d -= 9
        checksum += d
    return checksum % 10 == 0


